    def _vaa_score(self, ps):
        n = len(ps)
        if n < 252:
            return None
        p0 = ps.iloc[-1]
        p1m = ps.iloc[-21]
        p3m = ps.iloc[-63]
        p6m = ps.iloc[-126]
        p12m = ps.iloc[-252]
        if any(p <= 0 for p in [p0, p1m, p3m, p6m, p12m]):
            return None
        return (12 * (p0 / p1m - 1) +
                 4 * (p0 / p3m - 1) +
                 2 * (p0 / p6m - 1) +
                 1 * (p0 / p12m - 1))

    def generate_signals(self, data: dict) -> dict:
        symbols = list(data.keys())
        prices = pd.DataFrame({s: data[s]['close'] for s in symbols})
        all_dates = prices.index

        signals = {}
        for sym in symbols:
            signals[sym] = pd.DataFrame(
                {'signal': 0, 'size_pct': 0.0}, index=data[sym].index
            )

        if len(all_dates) < 253:
            return signals

        offensive = [s for s in ['QQQ', 'SPY', 'IWM', 'EFA'] if s in symbols]
        defensive = [s for s in ['TLT', 'AGG', 'GLD'] if s in symbols]

        prev_hy_spread = None
        prev_fedfunds = None
        prev_fedfunds_m1 = None
        current_weights = {}

        for i, date in enumerate(all_dates):
            if i < 252:
                continue
            if i % self.params['rebal_freq'] != 0:
