            if fedfunds is not None and prev_fedfunds is not None and prev_fedfunds_m1 is not None:
                if fedfunds - prev_fedfunds_m1 > 1.0:
                    rate_hiking_fast = True
            if fedfunds is not None:
                prev_fedfunds_m1 = prev_fedfunds
                prev_fedfunds = fedfunds

            panic_buy = vix is not None and vix > 35
            elevated_vix = vix is not None and 25 < vix <= 35

