                if rate_hiking_fast or hy_rising_fast:
                    # Macro danger: split equity/defensive
                    if def_scores:
                        top_def = max(def_scores.items(), key=lambda x: x[1])[0]
                        new_weights = {top_eq: 0.35, top_def: 0.45}
                    else:
