            else:
                # n_positive >= 2: Bull market — concentrate aggressively
                sorted_off = sorted(pos_assets.items(), key=lambda x: x[1], reverse=True)
                top_names_2 = [x[0] for x in sorted_off[:2]]

                # QQQ preference: if positive and in top-2 by score, prefer it
                if 'QQQ' in pos_assets and 'QQQ' in top_names_2:
                    top1 = 'QQQ'
                    others = [x for x in sorted_off if x[0] != 'QQQ']
                    top2 = others[0][0] if others else None
                else:
                    top1 = sorted_off[0][0]
                    top2 = sorted_off[1][0] if len(sorted_off) > 1 else None

                if rate_hiking_fast:
                    # Fast rate hikes: tilt defensive even in bull breadth
                    if def_scores:
                        top_def = max(def_scores.items(), key=lambda x: x[1])[0]
                        new_weights = {top1: 0.45, top_def: 0.35}
                    else:
                        new_weights = {top1: 0.65}

                elif n_positive >= 3:
                    # Strong breadth: concentrate heavily in top asset
                    if n_positive == 4:
                        new_weights = {top1: 0.95}
                    else:  # 3 positive
