                    elif top2:
                        new_weights = {top1: 0.65, top2: 0.25}
                    else:
                        new_weights = {top1: 0.85}

            self._apply_signals(signals, current_weights, new_weights, date, symbols)
            current_weights = dict(new_weights)

        return signals

    def _apply_signals(self, signals, current_weights, new_weights, date, symbols):
        all_syms = set(current_weights) | set(new_weights)
        for sym in symbols:
            if sym not in all_syms:
                continue
            old_w = current_weights.get(sym, 0.0)
            new_w = new_weights.get(sym, 0.0)
            if old_w == 0.0 and new_w > 0.0:
                signals[sym].loc[date, 'signal'] = 1
                signals[sym].loc[date, 'size_pct'] = new_w
            elif old_w > 0.0 and new_w == 0.0:
                signals[sym].loc[date, 'signal'] = -1
                signals[sym].loc[date, 'size_pct'] = 0.0
            elif old_w > 0.0 and new_w > 0.0:
                if abs(new_w - old_w) > 0.02:
                    signals[sym].loc[date, 'signal'] = 2
                    signals[sym].loc[date, 'size_pct'] = new_w
